449→func handleTLSConfig(cfg *CombinedConfig) (*tls.Config, bool, error) {
450→	tlsCfg := cfg.Server.TLS
451→
452→	if tlsCfg.LetsEncrypt.AWSRoute53 {
453→		log.Debugf("using Let's Encrypt DNS resolver with Route 53 support")
454→		r53 := encryption.Route53TLS{
455→			DataDir: tlsCfg.LetsEncrypt.DataDir,
456→			Email:   tlsCfg.LetsEncrypt.Email,
457→			Domains: tlsCfg.LetsEncrypt.Domains,
458→		}
459→		tc, err := r53.GetCertificate()
460→		if err != nil {
461→			return nil, false, err
462→		}
463→		return tc, true, nil
464→	}
465→
466→	if cfg.HasLetsEncrypt() {
467→		log.Infof("setting up TLS with Let's Encrypt")
468→		certManager, err := encryption.CreateCertManager(tlsCfg.LetsEncrypt.DataDir, tlsCfg.LetsEncrypt.Domains...)
469→		if err != nil {
470→			return nil, false, fmt.Errorf("failed creating LetsEncrypt cert manager: %w", err)
471→		}
472→		return certManager.TLSConfig(), true, nil
473→	}
474→
475→	if cfg.HasTLSCert() {
476→		log.Debugf("using file based TLS config")
477→		tc, err := encryption.LoadTLSConfig(tlsCfg.CertFile, tlsCfg.KeyFile)
478→		if err != nil {
479→			return nil, false, err
480→		}
481→		return tc, true, nil
482→	}
483→
484→	return nil, false, nil
485→}
