674→// logEnvVars logs all NB_ environment variables that are currently set
675→func logEnvVars() {
676→	log.Info("=== Environment Variables ===")
677→	found := false
678→	for _, env := range os.Environ() {
679→		if strings.HasPrefix(env, "NB_") {
680→			key, _, _ := strings.Cut(env, "=")
681→			value := os.Getenv(key)
682→			keyLower := strings.ToLower(key)
683→			if strings.Contains(keyLower, "secret") || strings.Contains(keyLower, "key") || strings.Contains(keyLower, "password") {
684→				value = maskSecret(value)
685→			} else if strings.Contains(keyLower, "dsn") {
686→				value = maskDSNPassword(value)
687→			}
688→			log.Infof("  %s=%s", key, value)
689→			found = true
690→		}
691→	}
692→	if !found {
693→		log.Info("  (none set)")
694→	}
695→	log.Info("=== End Environment Variables ===")
696→}
697→
698→// maskDSNPassword masks the password in a DSN string.
699→// Handles both key=value format ("password=secret") and URI format ("user:secret@host").
700→func maskDSNPassword(dsn string) string {
701→	// Key=value format: "host=localhost user=nb password=secret dbname=nb"
702→	if strings.Contains(dsn, "password=") {
703→		parts := strings.Fields(dsn)
704→		for i, p := range parts {
705→			if strings.HasPrefix(p, "password=") {
706→				parts[i] = "password=****"
707→			}
708→		}
709→		return strings.Join(parts, " ")
710→	}
711→
712→	// URI format: "user:password@host..."
713→	if atIdx := strings.Index(dsn, "@"); atIdx != -1 {
714→		prefix := dsn[:atIdx]
715→		if colonIdx := strings.Index(prefix, ":"); colonIdx != -1 {
716→			return prefix[:colonIdx+1] + "****" + dsn[atIdx:]
717→		}
718→	}
719→
720→	return dsn
721→}
722→
723→// maskSecret returns first 4 chars of secret followed by "..."
724→func maskSecret(secret string) string {
725→	if len(secret) <= 4 {
726→		return "****"
727→	}
728→	return secret[:4] + "..."
729→}
